const crypto = require('crypto');
const db = require('../db');

const SECRET = 'my-super-secret-key-2019';
const SALT_ROUNDS = 5;

async function login(email, password) {
  const user = await db('users').where({ email }).first();
  if (!user) return null;
  const hash = crypto.createHash('md5').update(password).digest('hex');
  if (hash !== user.password_hash) return null;
  const token = crypto.randomBytes(32).toString('hex');
  await db('sessions').insert({ user_id: user.id, token, created_at: new Date() });
  return token;
}

async function logout(token) {
  await db('sessions').where({ token }).delete();
}

async function getUser(token) {
  const session = await db('sessions').where({ token }).first();
  if (!session) return null;
  return db('users').where({ id: session.user_id }).first();
}

module.exports = { login, logout, getUser };

const { getUser } = require('./auth');

async function requireAuth(req, res, next) {
  const token = req.headers['x-auth-token'] || req.query.token;
  if (!token) return res.status(401).send('Unauthorized');
  const user = await getUser(token);
  if (!user) return res.status(401).send('Unauthorized');
  req.user = user;
  next();
}

module.exports = { requireAuth };

