const crypto = require('crypto');
const bcrypt = require('bcrypt');
const db = require('../db');

const BCRYPT_ROUNDS = 12;
const SESSION_TTL_DAYS = 30;

async function login(email, password) {
  try {
    const user = await db('users').where({ email }).first();
    if (!user) {
      // Constant-time response even for missing users
      await bcrypt.compare(password, '$2b$12$invalidhashpadding...........');
      return null;
    }
    const valid = await bcrypt.compare(password, user.password_hash);
    if (!valid) return null;
    const token = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + SESSION_TTL_DAYS * 86400000);
    await db('sessions').insert({ user_id: user.id, token, expires_at: expiresAt });
    return token;
  } catch (err) {
    throw new Error('Login failed: ' + err.message);
  }
}

async function logout(token) {
  await db('sessions').where({ token }).delete();
}

async function getUser(token) {
  const session = await db('sessions')
    .where({ token })
    .where('expires_at', '>', new Date())
    .first();
  if (!session) return null;
  return db('users').where({ id: session.user_id }).first();
}

module.exports = { login, logout, getUser };
